For production applications, you need automated, continuous dependency monitoring with multiple layers of defense. This catches vulnerabilities as they're disclosed and prevents compromised packages from reaching production.

**PRODUCTION PATTERN**:

```javascript
// security/dependency-scanner.js
const { execSync } = require('child_process');
const fs = require('fs');
const https = require('https');
const crypto = require('crypto');

class DependencySecurityScanner {
    constructor(config) {
        this.config = {
            maxVulnerabilitySeverity: 'moderate', // low, moderate, high, critical
            allowedLicenses: ['MIT', 'Apache-2.0', 'BSD-3-Clause', 'ISC'],
            blockedPackages: ['event-stream', 'flatmap-stream'], // Known compromised
            maxPackageAge: 365 * 2, // Days - warn on unmaintained packages
            requireLockfile: true,
            ...config
        };
        this.findings = [];
    }

    async runFullScan() {
        console.log('[Security] Starting comprehensive dependency scan...');

        const results = {
            timestamp: new Date().toISOString(),
            lockfileIntegrity: await this.verifyLockfileIntegrity(),
            vulnerabilities: await this.scanVulnerabilities(),
            licenses: await this.auditLicenses(),
            blockedPackages: this.checkBlockedPackages(),
            outdatedPackages: await this.checkOutdated(),
            supplyChainRisks: await this.assessSupplyChainRisk()
        };

        return this.generateReport(results);
    }

    async verifyLockfileIntegrity() {
        console.log('[Security] Verifying package-lock.json integrity...');

        if (!fs.existsSync('package-lock.json')) {
            throw new Error('CRITICAL: package-lock.json missing - builds are not reproducible');
        }

        const lockfile = JSON.parse(fs.readFileSync('package-lock.json', 'utf8'));
        const integrityIssues = [];

        // Verify all packages have integrity hashes
        const checkIntegrity = (packages, path = '') => {
            for (const [name, pkg] of Object.entries(packages || {})) {
                const fullPath = path ? `${path}/${name}` : name;

                if (!pkg.integrity && pkg.resolved) {
                    integrityIssues.push({
                        package: fullPath,
                        issue: 'Missing integrity hash',
                        severity: 'high'
                    });
                }

                // Check for suspicious registries
                if (pkg.resolved && !pkg.resolved.startsWith('https://registry.npmjs.org/')) {
                    integrityIssues.push({
                        package: fullPath,
                        issue: `Non-standard registry: ${pkg.resolved}`,
                        severity: 'critical'
                    });
                }

                if (pkg.dependencies) {
                    checkIntegrity(pkg.dependencies, fullPath);
                }
            }
        };

        checkIntegrity(lockfile.packages || lockfile.dependencies);

        return {
            valid: integrityIssues.length === 0,
            issues: integrityIssues,
            lockfileVersion: lockfile.lockfileVersion
        };
    }

    async scanVulnerabilities() {
        console.log('[Security] Scanning for known vulnerabilities...');

        try {
            // Run npm audit
            const auditOutput = execSync('npm audit --json', { 
                encoding: 'utf8',
                maxBuffer: 50 * 1024 * 1024 // 50MB buffer for large projects
            });
            const audit = JSON.parse(auditOutput);

            return {
                totalVulnerabilities: audit.metadata?.vulnerabilities || {},
                advisories: Object.values(audit.advisories || {}),
                criticalCount: audit.metadata?.vulnerabilities?.critical || 0,
                highCount: audit.metadata?.vulnerabilities?.high || 0
            };
        } catch (error) {
            // npm audit exits with non-zero when vulnerabilities found
            if (error.stdout) {
                const audit = JSON.parse(error.stdout);
                return {
                    totalVulnerabilities: audit.metadata?.vulnerabilities || {},
                    advisories: Object.values(audit.advisories || {}),
                    criticalCount: audit.metadata?.vulnerabilities?.critical || 0,
                    highCount: audit.metadata?.vulnerabilities?.high || 0
                };
            }
            throw error;
        }
    }

    checkBlockedPackages() {
        console.log('[Security] Checking for blocked packages...');

        const lockfile = JSON.parse(fs.readFileSync('package-lock.json', 'utf8'));
        const blocked = [];

        const checkPackages = (packages) => {
            for (const [name, pkg] of Object.entries(packages || {})) {
                const pkgName = name.replace(/^node_modules\//, '');
                if (this.config.blockedPackages.includes(pkgName)) {
                    blocked.push({
                        package: pkgName,
                        version: pkg.version,
                        reason: 'Package is on security blocklist'
                    });
                }
            }
        };

        checkPackages(lockfile.packages || lockfile.dependencies);

        return { blocked, count: blocked.length };
    }

    async assessSupplyChainRisk() {
        console.log('[Security] Assessing supply chain risks...');

        const packageJson = JSON.parse(fs.readFileSync('package.json', 'utf8'));
        const allDeps = {
            ...packageJson.dependencies,
            ...packageJson.devDependencies
        };

        const risks = [];

        for (const [name, version] of Object.entries(allDeps)) {
            // Check for dangerous version specifiers
            if (version === '*' || version === 'latest') {
                risks.push({
                    package: name,
                    risk: 'Uses wildcard/latest version - vulnerable to hijacking',
                    severity: 'critical'
                });
            } else if (version.startsWith('^') || version.startsWith('~')) {
                risks.push({
                    package: name,
                    risk: 'Uses semver range - may auto-update to vulnerable version',
                    severity: 'medium'
                });
            }

            // Check for git dependencies (potential supply chain risk)
            if (version.includes('github.com') || version.includes('git+')) {
                risks.push({
                    package: name,
                    risk: 'Git dependency - not verified through npm registry',
                    severity: 'high'
                });
            }
        }

        return { risks, count: risks.length };
    }

    generateReport(results) {
        const report = {
            ...results,
            summary: {
                passed: true,
                criticalIssues: 0,
                recommendations: []
            }
        };

        // Evaluate critical issues
        if (results.vulnerabilities.criticalCount > 0) {
            report.summary.passed = false;
            report.summary.criticalIssues += results.vulnerabilities.criticalCount;
            report.summary.recommendations.push('Fix critical vulnerabilities immediately');
        }

        if (results.blockedPackages.count > 0) {
            report.summary.passed = false;
            report.summary.criticalIssues += results.blockedPackages.count;
            report.summary.recommendations.push('Remove blocked packages');
        }

        if (!results.lockfileIntegrity.valid) {
            report.summary.passed = false;
            report.summary.recommendations.push('Fix lockfile integrity issues');
        }

        return report;
    }
}

module.exports = { DependencySecurityScanner };
