Setting up continuous dependency scanning is essential for catching vulnerabilities before they reach production. The 2023 Retool breach demonstrated how supply chain attacks through dependencies can bypass traditional security controls.

**PRODUCTION PATTERN**:

```go
package main

import (
	"bytes"
	"context"
	"encoding/json"
	"fmt"
	"io"
	"log/slog"
	"net/http"
	"os"
	"os/exec"
	"time"

	"golang.org/x/vuln/scan"
)

// DependencyScanner handles vulnerability scanning
type DependencyScanner struct {
	logger         *slog.Logger
	alertWebhook   string
	scanInterval   time.Duration
	allowedModules map[string]bool
}

// VulnReport represents a vulnerability scan result
type VulnReport struct {
	Timestamp     time.Time           `json:"timestamp"`
	Module        string              `json:"module"`
	Findings      []VulnerabilityInfo `json:"findings"`
	BlockPipeline bool                `json:"block_pipeline"`
}

// VulnerabilityInfo contains details about a single vulnerability
type VulnerabilityInfo struct {
	ID          string   `json:"id"`
	Severity    string   `json:"severity"`
	Affected    string   `json:"affected"`
	Fixed       string   `json:"fixed"`
	Description string   `json:"description"`
	Aliases     []string `json:"aliases"`
}

// NewDependencyScanner creates a configured scanner
func NewDependencyScanner(logger *slog.Logger, alertWebhook string) *DependencyScanner {
	return &DependencyScanner{
		logger:       logger,
		alertWebhook: alertWebhook,
		scanInterval: 24 * time.Hour,
		allowedModules: map[string]bool{
			"github.com/approved/lib": true,
			"golang.org/x":            true,
		},
	}
}

// ScanDependencies runs govulncheck and analyzes results
func (ds *DependencyScanner) ScanDependencies(ctx context.Context, modulePath string) (*VulnReport, error) {
	ds.logger.Info("Starting dependency vulnerability scan",
		"module", modulePath,
		"timestamp", time.Now().UTC())

	// Run govulncheck
	cmd := exec.CommandContext(ctx, "govulncheck", "-json", "./...")
	cmd.Dir = modulePath

	var stdout, stderr bytes.Buffer
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr

	if err := cmd.Run(); err != nil {
		// govulncheck returns non-zero when vulns found
		ds.logger.Warn("govulncheck completed with findings", "stderr", stderr.String())
	}

	report := &VulnReport{
		Timestamp:     time.Now().UTC(),
		Module:        modulePath,
		Findings:      []VulnerabilityInfo{},
		BlockPipeline: false,
	}

	// Parse JSON output
	if err := ds.parseVulnCheckOutput(&stdout, report); err != nil {
		return nil, fmt.Errorf("failed to parse vuln output: %w", err)
	}

	// Check severity and determine if pipeline should be blocked
	for _, finding := range report.Findings {
		if finding.Severity == "CRITICAL" || finding.Severity == "HIGH" {
			report.BlockPipeline = true
			ds.logger.Error("Critical vulnerability detected",
				"id", finding.ID,
				"severity", finding.Severity,
				"affected", finding.Affected)

			// Send immediate alert
			ds.sendAlert(ctx, finding)
		}
	}

	return report, nil
}

// VerifyModuleIntegrity checks go.sum integrity
func (ds *DependencyScanner) VerifyModuleIntegrity(ctx context.Context, modulePath string) error {
	ds.logger.Info("Verifying module integrity", "module", modulePath)

	// Run go mod verify
	cmd := exec.CommandContext(ctx, "go", "mod", "verify")
	cmd.Dir = modulePath

	output, err := cmd.CombinedOutput()
	if err != nil {
