**Key Security Controls**:
- Pin dependency versions with caret (^) for controlled updates within major version
- Include roave/security-advisories which prevents installing packages with known CVEs
- Run `composer audit` automatically after install to check for vulnerabilities
- Never use wildcard (*) version constraints in production applications
- Commit composer.lock to ensure consistent versions across all environments

Managing dependencies across multiple applications requires automated scanning, centralized monitoring, and rapid patch deployment. Here's a production-ready approach.

**PRODUCTION PATTERN**:

```php
<?php
// scripts/DependencySecurityScanner.php
namespace App\Security;

use GuzzleHttp\Client;
use Monolog\Logger;
use Monolog\Handler\StreamHandler;
use Monolog\Handler\SlackHandler;

class DependencySecurityScanner
{
    private Logger $logger;
    private Client $httpClient;
    private array $config;
    private const PACKAGIST_API = 'https://packagist.org/packages/';
    private const GITHUB_ADVISORY_API = 'https://api.github.com/advisories';

    public function __construct(array $config)
    {
        $this->config = $config;
        $this->logger = new Logger('security-scanner');
        $this->logger->pushHandler(
            new StreamHandler('/var/log/security/dependency-audit.log', Logger::WARNING)
        );

        if (!empty($config['slack_webhook'])) {
            $this->logger->pushHandler(
                new SlackHandler(
                    $config['slack_webhook'],
                    '#security-alerts',
                    'DependencyBot',
                    true,
                    ':shield:',
                    Logger::CRITICAL
                )
            );
        }

        $this->httpClient = new Client([
            'timeout' => 30,
            'headers' => [
                'Accept' => 'application/vnd.github+json',
                'Authorization' => 'Bearer ' . ($config['github_token'] ?? '')
            ]
        ]);
    }

    public function scanComposerLock(string $lockFilePath): array
    {
        if (!file_exists($lockFilePath)) {
            throw new \RuntimeException("composer.lock not found: {$lockFilePath}");
        }

        $lockContent = json_decode(file_get_contents($lockFilePath), true);
        if (json_last_error() !== JSON_ERROR_NONE) {
            throw new \RuntimeException('Invalid composer.lock format');
        }

        $vulnerabilities = [];
        $packages = array_merge(
            $lockContent['packages'] ?? [],
            $lockContent['packages-dev'] ?? []
        );

        foreach ($packages as $package) {
            $packageVulns = $this->checkPackageAdvisories(
                $package['name'],
                $package['version']
            );

            if (!empty($packageVulns)) {
                $vulnerabilities[$package['name']] = [
                    'installed_version' => $package['version'],
                    'vulnerabilities' => $packageVulns
                ];
            }
        }

        return $vulnerabilities;
    }

    private function checkPackageAdvisories(string $packageName, string $version): array
    {
        $advisories = [];

        // Check GitHub Security Advisories
        try {
            $response = $this->httpClient->get(self::GITHUB_ADVISORY_API, [
                'query' => [
                    'ecosystem' => 'composer',
                    'package' => $packageName,
                    'severity' => 'high,critical'
                ]
            ]);

            $data = json_decode($response->getBody()->getContents(), true);

            foreach ($data as $advisory) {
                if ($this->isVersionAffected($version, $advisory['vulnerable_version_range'] ?? '')) {
                    $advisories[] = [
                        'id' => $advisory['ghsa_id'],
                        'cve' => $advisory['cve_id'] ?? 'N/A',
                        'severity' => $advisory['severity'],
                        'title' => $advisory['summary'],
                        'patched_versions' => $advisory['patched_versions'] ?? [],
                        'published_at' => $advisory['published_at']
                    ];
                }
            }
        } catch (\Exception $e) {
            $this->logger->warning("Failed to check advisories for {$packageName}: " . $e->getMessage());
        }

        return $advisories;
    }

    private function isVersionAffected(string $installedVersion, string $vulnerableRange): bool
    {
        // Simplified version check - production should use Composer\Semver\Semver
        return \Composer\Semver\Semver::satisfies($installedVersion, $vulnerableRange);
    }

    public function generateReport(array $vulnerabilities): void
    {
        $criticalCount = 0;
        $highCount = 0;

        foreach ($vulnerabilities as $package => $data) {
            foreach ($data['vulnerabilities'] as $vuln) {
                if ($vuln['severity'] === 'critical') $criticalCount++;
                if ($vuln['severity'] === 'high') $highCount++;

                $this->logger->log(
                    $vuln['severity'] === 'critical' ? Logger::CRITICAL : Logger::WARNING,
                    "VULNERABLE DEPENDENCY: {$package}@{$data['installed_version']}",
                    [
                        'cve' => $vuln['cve'],
                        'ghsa' => $vuln['id'],
                        'title' => $vuln['title'],
                        'remediation' => 'Update to: ' . implode(' or ', $vuln['patched_versions'])
                    ]
                );
            }
        }

        // Alert on critical vulnerabilities
        if ($criticalCount > 0) {
            $this->logger->critical(
                "CRITICAL: {$criticalCount} critical vulnerabilities found!",
                ['total_high' => $highCount, 'packages' => array_keys($vulnerabilities)]
            );
        }
    }
}
