        id: audit
        run: |
          composer audit --format=json > audit-results.json || true
          echo "vulnerabilities=$(jq '.advisories | length' audit-results.json)" >> $GITHUB_OUTPUT

      - name: Check for roave/security-advisories
        run: |
          if ! composer show roave/security-advisories 2>/dev/null; then
            echo "::error::roave/security-advisories not installed!"
            exit 1
          fi

      - name: Run Enlightn Security Checker
        run: ./vendor/bin/security-checker security:check composer.lock

      - name: Fail on Critical Vulnerabilities
        if: steps.audit.outputs.vulnerabilities > 0
        run: |
          echo "::error::Found ${{ steps.audit.outputs.vulnerabilities }} vulnerabilities"
          cat audit-results.json
          exit 1

      - name: Upload Audit Report
        uses: actions/upload-artifact@v4
        with:
          name: security-audit-report
          path: audit-results.json
