```php
<?php
// app/Console/Commands/SecurityAuditCommand.php
namespace App\Console\Commands;

use Illuminate\Console\Command;
use Illuminate\Support\Facades\Http;
use Illuminate\Support\Facades\Cache;
use App\Security\DependencySecurityScanner;

class SecurityAuditCommand extends Command
{
    protected $signature = 'security:audit 
                            {--fail-on-high : Exit with error on high severity}
                            {--update-check : Check for available updates}
                            {--json : Output as JSON}';

    protected $description = 'Audit dependencies for known security vulnerabilities';

    public function handle(): int
    {
        $this->info('Starting dependency security audit...');

        // Run composer audit
        $auditOutput = [];
        $exitCode = 0;
        exec('composer audit --format=json 2>&1', $auditOutput, $exitCode);

        $auditData = json_decode(implode('', $auditOutput), true);
        $advisories = $auditData['advisories'] ?? [];

        if (empty($advisories)) {
            $this->info('✅ No known vulnerabilities found!');
            return Command::SUCCESS;
        }

        // Display vulnerabilities
        $criticalCount = 0;
        $highCount = 0;

        foreach ($advisories as $package => $packageAdvisories) {
            foreach ($packageAdvisories as $advisory) {
                $severity = strtolower($advisory['severity'] ?? 'unknown');

                if ($severity === 'critical') {
                    $criticalCount++;
                    $this->error("🚨 CRITICAL: {$package}");
                } elseif ($severity === 'high') {
                    $highCount++;
                    $this->warn("⚠️  HIGH: {$package}");
                } else {
                    $this->line("ℹ️  {$severity}: {$package}");
                }

                $this->line("   CVE: " . ($advisory['cve'] ?? 'N/A'));
                $this->line("   Title: " . ($advisory['title'] ?? 'N/A'));
                $this->line("   Affected: " . ($advisory['affectedVersions'] ?? 'N/A'));
                $this->line('');
            }
        }

        // Summary
        $this->newLine();
        $this->error("Found {$criticalCount} critical and {$highCount} high severity vulnerabilities");

        // Check for updates if requested
        if ($this->option('update-check')) {
            $this->info('\nChecking for available updates...');
            exec('composer outdated --direct --format=json', $outdatedOutput);
            $outdated = json_decode(implode('', $outdatedOutput), true);

            foreach ($outdated['installed'] ?? [] as $pkg) {
                $this->line("📦 {$pkg['name']}: {$pkg['version']} → {$pkg['latest']}");
            }
        }

        // Exit with error if critical vulns found
        if ($criticalCount > 0 || ($this->option('fail-on-high') && $highCount > 0)) {
            return Command::FAILURE;
        }

        return Command::SUCCESS;
    }
}
